    SELECT COMPLAINT_SEQ.NEXTVAL FROM DUAL

INSERT INTO COMPLAINT (
    DCL_NO, DCL_BBS_NO, EMP_ID, DCL_CN, DCL_DT, DCL_STTS
) VALUES (
    #{dclNo}, #{dclBbsNo}, #{empId}, #{dclCn}, SYSDATE, '신고접수'
)

mapper.select:
SELECT A.DCL_NO, A.DCL_BBS_NO, A.EMP_ID, A.DCL_CN, A.DCL_DT, A.DCL_STTS, B.EMP_NM AS reporterNm, C.BBS_NM AS bbsTitle, C.BBS_CN AS bbsCn, C.EMP_ID AS writerId FROM COMPLAINT A LEFT OUTER JOIN EMPLOYEE B ON(A.EMP_ID = B.EMP_ID) LEFT OUTER JOIN BBS_BOARD C ON(A.DCL_BBS_NO = C.BBS_NO) WHERE 1=1
AND A.DCL_STTS = #{dclStts}
ORDER BY A.DCL_NO DESC

mapper.update:
UPDATE BBS_BOARD 
SET BBS_REPORT_CNT = NVL(BBS_REPORT_CNT, 0) + 1
WHERE BBS_NO = #{bbsNo}

mapper.select:
SELECT NVL(BBS_REPORT_CNT, 0)
FROM BBS_BOARD
WHERE BBS_NO = #{bbsNo}

mapper.update:
UPDATE BBS_BOARD 
SET BBS_DEL_YN = 'D' 
WHERE BBS_NO = #{bbsNo}

UPDATE BBS_BOARD
   SET BBS_REPORT_CNT = 0  
WHERE BBS_NO = #{bbsNo}
